+
+    it('should have no country selected when defaultCountry prop is omitted', () => {
+        const spy = jest.fn();
+        const { getByRole } = render(<PhoneInput value="" data-testid="input" onChange={spy} />);
+        const button = getByRole('button') as HTMLButtonElement;
+        expect(getCountry(button)).toBe(null);
+    });
+
+    it('should adopt defaultCountry after mount once and ignore subsequent changes', () => {
+        const spy = jest.fn();
+        const { getByRole, rerender } = render(<PhoneInput value="" data-testid="input" onChange={spy} />);
+        const button = getByRole('button') as HTMLButtonElement;
+        expect(getCountry(button)).toBe(null);
+        rerender(<PhoneInput value="" defaultCountry="US" data-testid="input" onChange={spy} />);
+        expect(getCountry(button)).toBe('United States');
+        rerender(<PhoneInput value="" defaultCountry="CH" data-testid="input" onChange={spy} />);
+        expect(getCountry(button)).toBe('United States');
+        rerender(<PhoneInput value="" defaultCountry="" data-testid="input" onChange={spy} />);
+        expect(getCountry(button)).toBe('United States');
+    });
+});
